mapper.select:
SELECT task_type AS taskType, progress, claimed
FROM daily_task_progress
WHERE user_id = #{userId} AND task_date = #{taskDate}

mapper.insert:
INSERT INTO daily_task_progress (user_id, task_date, task_type, progress, claimed)
VALUES (#{userId}, #{taskDate}, #{taskType}, #{increment}, 0)
ON DUPLICATE KEY UPDATE progress = progress + #{increment}

mapper.update:
UPDATE daily_task_progress
SET claimed = 1
WHERE user_id = #{userId} AND task_date = #{taskDate} AND task_type = #{taskType}

mapper.select:
SELECT achievement_type AS achievementType, claimed
FROM achievement_progress
WHERE user_id = #{userId} AND achievement_type = #{achievementType}

